<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Personal Expense Tracker</title>
<style>
  * { box-sizing: border-box; }
  body {
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    max-width: 820px;
    margin: 0 auto;
    padding: 20px;
    background: #f4f5f7;
    color: #1f2937;
    line-height: 1.4;
  }
  h1 { margin: 0 0 16px; font-size: 1.5rem; }
  h2 { margin: 0 0 10px; font-size: 1.05rem; color: #374151; }
  section {
    background: #fff;
    border: 1px solid #e5e7eb;
    border-radius: 8px;
    padding: 16px;
    margin-bottom: 16px;
    box-shadow: 0 1px 2px rgba(0,0,0,0.03);
  }
  form#entry-form {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
    gap: 10px;
    align-items: end;
  }
  label { display: block; font-size: 0.8rem; color: #4b5563; margin-bottom: 3px; }
  input, select, button {
    font: inherit;
    padding: 7px 9px;
    border: 1px solid #d1d5db;
    border-radius: 5px;
    width: 100%;
    background: #fff;
    color: #111827;
  }
  input:focus, select:focus { outline: 2px solid #2563eb33; border-color: #2563eb; }
  button {
    background: #2563eb;
    color: #fff;
    border: 1px solid #2563eb;
    cursor: pointer;
    font-weight: 500;
  }
  button:hover { background: #1d4ed8; }
  #form-error { color: #b91c1c; font-size: 0.9rem; min-height: 1.2em; margin-top: 10px; }
  .filters { display: flex; flex-wrap: wrap; gap: 12px; align-items: end; }
  .filters > div { min-width: 150px; }
  .filters button { background: #6b7280; border-color: #6b7280; }
  .filters button:hover { background: #4b5563; }
  .expense {
    display: grid;
    grid-template-columns: 90px 110px 120px 1fr 90px;
    gap: 10px;
    padding: 10px 8px;
    border-bottom: 1px solid #f1f5f9;
    align-items: center;
    font-size: 0.95rem;
  }
  .expense:last-child { border-bottom: none; }
  .expense .exp-amount { font-weight: 600; color: #111827; }
  .expense .exp-cat { color: #2563eb; text-transform: capitalize; }
  .expense .exp-date { color: #4b5563; font-variant-numeric: tabular-nums; }
  .expense .exp-note { color: #6b7280; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
  .exp-del {
    background: #dc2626;
    border: 1px solid #dc2626;
    color: #fff;
    padding: 5px 8px;
    cursor: pointer;
    border-radius: 4px;
  }
  .exp-del:hover { background: #b91c1c; }
  .empty { color: #9ca3af; font-style: italic; padding: 18px; text-align: center; }
  .summary { display: flex; flex-wrap: wrap; gap: 14px; align-items: center; }
  .summary-row { display: flex; align-items: center; gap: 8px; }
  #total { font-size: 1.5rem; font-weight: 700; color: #2563eb; font-variant-numeric: tabular-nums; }
  .cat-total {
    background: #eef2ff;
    color: #3730a3;
    padding: 6px 10px;
    border-radius: 999px;
    font-size: 0.85rem;
    font-variant-numeric: tabular-nums;
  }
  .footer-note { font-size: 0.75rem; color: #9ca3af; text-align: center; margin-top: 8px; }
</style>
</head>
<body>
  <h1>Personal Expense Tracker</h1>

  <section>
    <h2>Add Expense</h2>
    <form id="entry-form" novalidate>
      <div>
        <label for="amount">Amount</label>
        <input type="number" id="amount" step="0.01" min="0.01" placeholder="0.00">
      </div>
      <div>
        <label for="category">Category</label>
        <select id="category">
          <option value="groceries">groceries</option>
          <option value="transport">transport</option>
          <option value="bills">bills</option>
          <option value="fun">fun</option>
        </select>
      </div>
      <div>
        <label for="date">Date</label>
        <input type="date" id="date">
      </div>
      <div>
        <label for="note">Note (optional)</label>
        <input type="text" id="note" placeholder="What was it for?">
      </div>
      <div>
        <button type="submit" id="add-expense">Add Expense</button>
      </div>
    </form>
    <div id="form-error" role="alert" aria-live="polite"></div>
  </section>

  <section>
    <h2>Filters</h2>
    <div class="filters">
      <div>
        <label for="filter-category">Category</label>
        <select id="filter-category">
          <option value="all">all</option>
          <option value="groceries">groceries</option>
          <option value="transport">transport</option>
          <option value="bills">bills</option>
          <option value="fun">fun</option>
        </select>
      </div>
      <div>
        <label for="filter-from">From</label>
        <input type="date" id="filter-from">
      </div>
      <div>
        <label for="filter-to">To</label>
        <input type="date" id="filter-to">
      </div>
      <div>
        <button type="button" id="clear-filters">Clear filters</button>
      </div>
    </div>
  </section>

  <section>
    <h2>Expenses</h2>
    <div id="expense-list"></div>
  </section>

  <section>
    <h2>Summary (visible)</h2>
    <div class="summary">
      <div class="summary-row">Total: <span id="total">0.00</span></div>
    </div>
    <div class="summary" id="category-summary" style="margin-top: 12px;">
      <span class="cat-total" data-cat="groceries">groceries: 0.00</span>
      <span class="cat-total" data-cat="transport">transport: 0.00</span>
      <span class="cat-total" data-cat="bills">bills: 0.00</span>
      <span class="cat-total" data-cat="fun">fun: 0.00</span>
    </div>
    <div class="footer-note">All data is stored locally in your browser.</div>
  </section>

<script>
(function () {
  'use strict';

  var STORAGE_KEY = 'expense-tracker-v1';
  var CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];

  // ----- State -----
  var expenses = load();

  // ----- DOM refs -----
  var form         = document.getElementById('entry-form');
  var amountEl     = document.getElementById('amount');
  var categoryEl   = document.getElementById('category');
  var dateEl       = document.getElementById('date');
  var noteEl       = document.getElementById('note');
  var formError    = document.getElementById('form-error');
  var filterCatEl  = document.getElementById('filter-category');
  var filterFromEl = document.getElementById('filter-from');
  var filterToEl   = document.getElementById('filter-to');
  var clearBtn     = document.getElementById('clear-filters');
  var listEl       = document.getElementById('expense-list');
  var totalEl      = document.getElementById('total');

  // ----- Storage -----
  function load() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return [];
      var arr = JSON.parse(raw);
      return Array.isArray(arr) ? arr : [];
    } catch (e) {
      return [];
    }
  }
  function save() {
    try { localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses)); }
    catch (e) { /* quota or disabled */ }
  }

  // ----- Helpers -----
  function fmt(n) {
    var v = Number(n);
    if (!isFinite(v)) v = 0;
    return v.toFixed(2);
  }
  function escapeHtml(s) {
    return String(s == null ? '' : s).replace(/[&<>"']/g, function (ch) {
      return ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' })[ch];
    });
  }
  function todayISO() {
    var d = new Date();
    var m = String(d.getMonth() + 1);
    var day = String(d.getDate());
    return d.getFullYear() + '-' + (m.length < 2 ? '0' + m : m) + '-' + (day.length < 2 ? '0' + day : day);
  }

  // ----- Filter + render -----
  function getVisible() {
    var cat  = filterCatEl.value;
    var from = filterFromEl.value;
    var to   = filterToEl.value;
    return expenses.filter(function (e) {
      if (cat !== 'all' && e.category !== cat) return false;
      if (from && e.date < from) return false;
      if (to   && e.date > to)   return false;
      return true;
    });
  }

  function render() {
    var visible = getVisible();
    // Newest first: by date desc, then by insertion order desc
    visible.sort(function (a, b) {
      if (a.date !== b.date) return b.date.localeCompare(a.date);
      return (b.id || 0) - (a.id || 0);
    });

    // List
    listEl.innerHTML = '';
    if (visible.length === 0) {
      var empty = document.createElement('div');
      empty.className = 'empty';
      empty.textContent = expenses.length === 0
        ? 'No expenses yet. Add your first one above.'
        : 'No expenses match the current filters.';
      listEl.appendChild(empty);
    } else {
      var frag = document.createDocumentFragment();
      for (var i = 0; i < visible.length; i++) {
        var e = visible[i];
        var row = document.createElement('div');
        row.className = 'expense';
        row.innerHTML =
          '<span class="exp-amount">' + fmt(e.amount) + '</span>' +
          '<span class="exp-cat">' + escapeHtml(e.category) + '</span>' +
          '<span class="exp-date">' + escapeHtml(e.date) + '</span>' +
          '<span class="exp-note">' + escapeHtml(e.note || '') + '</span>' +
          '<button type="button" class="exp-del" data-id="' + e.id + '">Delete</button>';
        frag.appendChild(row);
      }
      listEl.appendChild(frag);
    }

    // Total
    var total = 0;
    for (var j = 0; j < visible.length; j++) total += Number(visible[j].amount) || 0;
    totalEl.textContent = fmt(total);

    // Per-category totals (only over visible expenses)
    var catTotals = {};
    for (var k = 0; k < CATEGORIES.length; k++) catTotals[CATEGORIES[k]] = 0;
    for (var m = 0; m < visible.length; m++) {
      var ex = visible[m];
      if (catTotals.hasOwnProperty(ex.category)) catTotals[ex.category] += Number(ex.amount) || 0;
    }
    for (var c = 0; c < CATEGORIES.length; c++) {
      var el = document.querySelector('.cat-total[data-cat="' + CATEGORIES[c] + '"]');
      if (el) el.textContent = CATEGORIES[c] + ': ' + fmt(catTotals[CATEGORIES[c]]);
    }
  }

  // ----- Form submission -----
  form.addEventListener('submit', function (ev) {
    ev.preventDefault();
    var raw = amountEl.value;

    if (raw === '' || raw === null) {
      formError.textContent = 'Please enter an amount.';
      amountEl.focus();
      return;
    }
    var amt = Number(raw);
    if (!isFinite(amt) || isNaN(amt)) {
      formError.textContent = 'Amount must be a number.';
      amountEl.focus();
      return;
    }
    if (amt <= 0) {
      formError.textContent = 'Amount must be greater than zero.';
      amountEl.focus();
      return;
    }
    var date = dateEl.value;
    if (!date) {
      formError.textContent = 'Please pick a date.';
      dateEl.focus();
      return;
    }

    expenses.push({
      id: Date.now() + Math.floor(Math.random() * 100000),
      amount: amt,
      category: categoryEl.value,
      date: date,
      note: noteEl.value.trim()
    });
    save();

    formError.textContent = '';
    amountEl.value = '';   // reset only the amount field, per spec
    amountEl.focus();
    render();
  });

  // ----- Delete (event delegation, immediate, no confirm) -----
  listEl.addEventListener('click', function (ev) {
    var t = ev.target;
    if (t && t.classList && t.classList.contains('exp-del')) {
      var id = t.getAttribute('data-id');
      expenses = expenses.filter(function (e) { return String(e.id) !== String(id); });
      save();
      render();
    }
  });

  // ----- Filters -----
  filterCatEl.addEventListener('change', render);
  filterFromEl.addEventListener('change', render);
  filterFromEl.addEventListener('input', render);
  filterToEl.addEventListener('change', render);
  filterToEl.addEventListener('input', render);

  clearBtn.addEventListener('click', function () {
    filterCatEl.value = 'all';
    filterFromEl.value = '';
    filterToEl.value = '';
    render();
  });

  // ----- Initial defaults -----
  if (!dateEl.value) dateEl.value = todayISO();
  render();
})();
</script>
</body>
</html>
